type ModelName = "claude-sonnet-4-6" | "gpt-4o" | "gemini-2-0-flash";
type TokenCount = number;
type MessageRole = "user" | "assistant" | "system";

interface ChatMessage {
  role: MessageRole;
  content: string;
  timestamp?: number; // The ? makes it optional
}

interface APIRequest {
  model: string;
  messages: ChatMessage[];
  max_tokens: number;
  temperature?: number;    // Optional field (can be omitted)
  system?: string;
}

// Union type — value must be exactly one of these strings
type FinishReason = "end_turn" | "max_tokens" | "stop_sequence" | "tool_use";

// Intersection type — must satisfy BOTH shapes simultaneously
type AuthenticatedRequest = APIRequest & { apiKey: string };

// Tuple type — array with fixed length and specific types at each index
type TokenPair = [number, number]; // [inputTokens, outputTokens]

// Function type
type StreamHandler = (chunk: StreamChunk) => void;

// Interface extension
interface BaseMessage {
  role: MessageRole;
  content: string;
}

interface SystemMessage extends BaseMessage {
  role: "system";
  cacheable?: boolean;
}

// Type alias intersection (equivalent to extension)
type ExtendedSystemMessage = BaseMessage & { role: "system"; cacheable?: boolean };

interface CompletionOptions {
  maxTokens: number;           // Required
  temperature?: number;        // Optional — may be undefined
  topP?: number;               // Optional
  stopSequences?: string[];    // Optional
}

interface ModelConfig {
  readonly modelId: string;    // Cannot be reassigned after creation
  maxContextWindow: number;
}

// Use interface — an object shape that may be extended
interface BaseRequest {
  model: string;
  maxTokens: number;
}

interface RequestWithTools extends BaseRequest {
  tools: ToolDefinition[];
}

// Use type — a union (can't do this with interface)
type ContentBlock =
  | { type: "text"; text: string }
  | { type: "image"; source: ImageSource }
  | { type: "tool_use"; id: string; name: string; input: unknown };

// A generic API response wrapper used across all endpoints
interface APIResponse<T> {
  data: T;
  error: string | null;
  requestId: string;
  usage: {
    inputTokens: number;
    outputTokens: number;
  };
}

// When used, T is replaced by the specific data shape
type CompletionResponse = APIResponse<ChatMessage>;
type EmbeddingResponse = APIResponse<number[]>;
type ToolCallResponse = APIResponse<ToolResult[]>;

async function callAPI<TResponse>(
  endpoint: string,
  body: APIRequest
): Promise<APIResponse<TResponse>> {
  const res = await fetch(endpoint, {
    method: "POST",
    body: JSON.stringify(body),
  });
  return res.json();
}

