// chat-session.ts
import type { ConversationState, Message, SendOptions, SendResult } from "./types";

export class ChatSession {
  private state: ConversationState;

  constructor(model: string, systemPrompt?: string) {
    this.state = {
      id: crypto.randomUUID(),
      messages: [],
      model,
      systemPrompt,
      totalTokensUsed: 0,
    };
  }

  async send(userText: string, options: SendOptions = {}): Promise<SendResult> {
    const userMessage: Message = {
      id: crypto.randomUUID(),
      role: "user",
      content: userText,
      timestamp: Date.now(),
    };

    this.state.messages.push(userMessage);

    // TypeScript enforces the correct request shape here
    const requestBody = {
      model: this.state.model,
      messages: this.state.messages.map(m => ({ role: m.role, content: m.content })),
      max_tokens: options.maxTokens ?? 2048,
      system: this.state.systemPrompt,
    };

    const response = await fetch("https://api.anthropic.com/v1/messages", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(requestBody),
    });

    const data = await response.json();
    const assistantText = data.content[0]?.text ?? "";

    const assistantMessage: Message = {
      id: crypto.randomUUID(),
      role: "assistant",
      content: assistantText,
      timestamp: Date.now(),
      tokenCount: data.usage.output_tokens,
    };

    this.state.messages.push(assistantMessage);
    this.state.totalTokensUsed += data.usage.input_tokens + data.usage.output_tokens;

    return {
      message: assistantMessage,
      inputTokens: data.usage.input_tokens,
      outputTokens: data.usage.output_tokens,
      finishReason: data.stop_reason,
    };
  }

  getHistory(): Message[] {
    return [...this.state.messages]; // Returns a copy to prevent mutation
  }
}

